import{Ct as e,ct as t,lt as n,q as r}from"./chunks/framework.BVmwMUcr.js";var i=JSON.parse(`{"title":"HEMC","description":"A food guide for the Higher Education Mega Center campus","frontmatter":{"lang":"en-US","title":"HEMC","description":"A food guide for the Higher Education Mega Center campus","llm_translated":true},"headers":[],"relativePath":"en/life/eat/hemc.md","filePath":"en/life/eat/hemc.md","lastUpdated":1784829332000}`),a={name:`en/life/eat/hemc.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /en/life/eat/hemc.md for this page in Markdown format</div><h1 id="hemc-food-guide" tabindex="-1">HEMC Food Guide <a class="header-anchor" href="#hemc-food-guide" aria-label="Permalink to “HEMC Food Guide”">​</a></h1><p><em>❤️ Please note: The following content is based on the editor&#39;s personal, subjective experience. Different people have different tastes when it comes to food. If you have more suggestions, feel free to leave a comment or submit a PR to contribute to this page ヾ(≧▽≦</em>)o_</p><h2 id="on-campus" tabindex="-1">On Campus <a class="header-anchor" href="#on-campus" aria-label="Permalink to “On Campus”">​</a></h2><h3 id="_1-canteen-1" tabindex="-1">1. Canteen 1 <a class="header-anchor" href="#_1-canteen-1" aria-label="Permalink to “1. Canteen 1”">​</a></h3><ul><li><p>Location: Next to East Gate 1 of the living area</p></li><li><p>Service hours: Before 9:00 AM, 11:30 - 13:00 PM, 16:30 - 19:00 PM</p></li></ul><h4 id="floor-features" tabindex="-1">Floor Features <a class="header-anchor" href="#floor-features" aria-label="Permalink to “Floor Features”">​</a></h4><ul><li><p>First floor: Student counters, vendor counters (fried noodles, malatang, etc.), convenience store, bakery</p></li><li><p>Second floor: Student counters (<strong>using trays</strong>), vendor counters</p></li><li><p>Third floor: Faculty dining area (students can also eat here), Northwest China cuisine restaurant</p></li></ul><h4 id="recommended-dishes" tabindex="-1">Recommended Dishes <a class="header-anchor" href="#recommended-dishes" aria-label="Permalink to “Recommended Dishes”">​</a></h4><ul><li><p>First floor:</p><ul><li>I personally think the fried noodles are pretty good. A lot of times when I study late and other counters are closed, I go get some [from nanako]</li></ul></li><li><p>Second floor:</p><ul><li>The student counters on the second floor use trays that let the oil drain off, which I personally find better than the first floor [from nanako]</li></ul></li><li><p>Third floor:</p><ul><li>The faculty dining area is a bit pricier but tastes slightly better than the student cafeteria [from nanako]</li></ul></li></ul><h3 id="_2-canteen-2" tabindex="-1">2. Canteen 2 <a class="header-anchor" href="#_2-canteen-2" aria-label="Permalink to “2. Canteen 2”">​</a></h3><ul><li><p>Location: Near North Gate 1 of the living area, next to the school clinic</p></li><li><p>Service hours: Before 9:00 AM, 11:30 - 13:00 PM, 16:30 - 19:00 PM</p></li></ul><h4 id="floor-features-1" tabindex="-1">Floor Features <a class="header-anchor" href="#floor-features-1" aria-label="Permalink to “Floor Features”">​</a></h4><ul><li><p>First floor: Student counters, vendor counters, convenience store</p></li><li><p>Second floor: Vendor counters</p></li><li><p>Third floor: Chunhuiyuan (outsourced restaurant)</p></li></ul><h4 id="recommended-dishes-1" tabindex="-1">Recommended Dishes <a class="header-anchor" href="#recommended-dishes-1" aria-label="Permalink to “Recommended Dishes”">​</a></h4><ul><li><p>First floor:</p><ul><li>Canteen 2&#39;s first floor has healthy meals with less oil, definitely recommend [from nanako]</li><li>The &quot;egg over rice&quot; on the first floor is also pretty good, but I wouldn&#39;t recommend the tomato sauce [from nanako]</li></ul></li><li><p>Second floor:</p><ul><li>The grilled rice on the second floor is decent in my opinion [from nanako]</li></ul></li><li><p>Third floor:</p><ul><li>The set meals on the third floor are the most affordable on that level, but the dishes are pretty much the same every day [from nanako]</li><li>The stone pot rice is tasty but can easily give you heatiness [from nanako]</li></ul></li></ul><h3 id="_3-xiya-supermarket" tabindex="-1">3. Xiya Supermarket <a class="header-anchor" href="#_3-xiya-supermarket" aria-label="Permalink to “3. Xiya Supermarket”">​</a></h3><ul><li><p>Location: Next to East Gate 1 of the living area, across from Canteen 1</p></li><li><p>There are a few shops on the second floor of Xiya</p></li><li><p>Service hours: (TBD, should be open along with the supermarket)</p></li></ul><h3 id="_4-mcdonald-s-meet-noodles-etc" tabindex="-1">4. McDonald&#39;s, Meet Noodles, etc. <a class="header-anchor" href="#_4-mcdonald-s-meet-noodles-etc" aria-label="Permalink to “4. McDonald&#39;s, Meet Noodles, etc.”">​</a></h3><ul><li><p>Location: Two-story commercial building next to the basketball court</p></li><li><p>Tenant shops: <strong>McDonald&#39;s</strong>, <strong>Meet Noodles</strong>, <strong>Luckin</strong>, <strong>Baodao</strong>, <strong>Huayuan Yunli</strong>, <strong>Kowloon Tea House</strong>, <strong>711</strong></p></li></ul><h2 id="off-campus" tabindex="-1">Off Campus <a class="header-anchor" href="#off-campus" aria-label="Permalink to “Off Campus”">​</a></h2><h3 id="_1-suishicun-village" tabindex="-1">1. Suishicun Village <a class="header-anchor" href="#_1-suishicun-village" aria-label="Permalink to “1. Suishicun Village”">​</a></h3><ul><li>Location: Outside the East Gate of the teaching area</li></ul><h3 id="_2-canteen-3" tabindex="-1">2. &quot;Canteen 3&quot; <a class="header-anchor" href="#_2-canteen-3" aria-label="Permalink to “2. &quot;Canteen 3&quot;”">​</a></h3><ul><li><p>Refers to the street vendors gathered outside East Gate 1 of the living area</p></li><li><p>Hygiene conditions are not very guaranteed</p></li><li><p>But offers many food options not available on campus</p></li></ul><h3 id="_3-other-locations-in-hemc" tabindex="-1">3. Other Locations in HEMC <a class="header-anchor" href="#_3-other-locations-in-hemc" aria-label="Permalink to “3. Other Locations in HEMC”">​</a></h3><ul><li><p>GoGo Xintiandi near Sun Yat-sen University</p></li><li><p>Beiting Village near South China Normal University</p></li><li><p>Guangdong University of Technology canteens</p></li></ul>`,27)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};